const ctx = $input.first().json;
if (!ctx.results?.opportunities || ctx.results.opportunities.length === 0) throw new Error('No jobs available to optimize for');
if (!ctx.results?.resume_profile) throw new Error('Missing original resume');

// We will optimize ONLY for the TOP 1 job by default as per user instruction.
const limit = $env.OPTIMIZATION_LIMIT ? parseInt($env.OPTIMIZATION_LIMIT) : 1;
const jobsToOptimize = ctx.results.opportunities.slice(0, limit);

return jobsToOptimize.map(job => ({
  json: { job, ctx }
}));

const loopRes = $input.first().json;
const sliced = $('Slice Top Jobs').item.json;

// Prepare inputs for util-ats-scoring using the TAILORED resume this time
const tailoredCtx = JSON.parse(JSON.stringify(sliced.ctx));
tailoredCtx.results.resume_profile = loopRes.tailored_resume; // Inject fake context for scoring

return [{
  json: {
    job: sliced.job,
    jd_intelligence: sliced.job.jd_intelligence,
    ctx: tailoredCtx
  }
}];

const originalJob = $('Slice Top Jobs').item.json.job;
const loopRes = $('Loop Iteration 1: Optimize').item.json;
const newAtsRes = $input.first().json.ats_evaluation;

const oldScore = originalJob.ats_evaluation.overall_score;
const newScore = newAtsRes.overall_score;

let finalStatus = loopRes.status;
if (newScore < oldScore) {
  finalStatus = 'REJECTED'; // Made it worse
}

return [{
  json: {
    job: originalJob,
    tailored_resume: finalStatus === 'OPTIMIZED' ? loopRes.tailored_resume : $('Slice Top Jobs').item.json.ctx.results.resume_profile,
    change_log: finalStatus === 'OPTIMIZED' ? loopRes.change_log : { summary_of_changes: 'Rejected due to lower score' },
    validation_report: loopRes.validation_report,
    status: finalStatus,
    ats_score_before: oldScore,
    ats_score_after: finalStatus === 'OPTIMIZED' ? newScore : oldScore
  }
}];

const allItems = $input.all();
const ctx = $('Slice Top Jobs').first().json.ctx;

// Attach the optimized resumes to the context
ctx.results.resume_versions = allItems.map(i => i.json);
ctx.agents_completed = [...(ctx.agents_completed || []), 'resume_refinement'];

return [{ json: ctx }];

const loopRes = $input.first().json;
const sliced = $('Slice Top Jobs').item.json;

return [{
  json: {
    job: sliced.job,
    tailored_resume: sliced.ctx.results.resume_profile, // Fallback to original
    change_log: { summary_of_changes: 'Validation Failed: ' + loopRes.validation_report.reason },
    validation_report: loopRes.validation_report,
    status: 'VALIDATION_FAILED',
    ats_score_before: sliced.job.ats_evaluation.overall_score,
    ats_score_after: sliced.job.ats_evaluation.overall_score
  }
}];
